import {useState, useMemo} from 'react'
import './App.css'

const App = () => {

 const [observed, setObserved] = useState(1);
 const [unobserved, setUnobserved] = useState(1);

 const inkrementObs = () => setObserved(observed + 1);
 const inkrementUnobs = () => setUnobserved(unobserved + 1);

 const createRandom = useMemo(() => {
  return ~~(Math.random()*1000)
 }, [observed])

 return (
  &lt;>
   &lt;p>
    {createRandom}
   &lt;/p>
   &lt;button onClick={inkrementObs}>
    {observed} (+1)
   &lt;/button>
   &lt;button onClick={inkrementUnobs}>
    {unobserved} (+1)
   &lt;/button>
  &lt;/>
 )
}

export default App

import React, {useState, memo} from 'react';

// Item mit memo: Rendert nur neu, wenn sich Props ändern
const ListItem = memo(({title, isHighlighted}) => {
 console.log(`Rendering: ${title}`); // Loggt NUR bei Änderungen der Props!
 return (
  &lt;li style={{fontWeight: isHighlighted ? 'bold' : 'normal'}}>
   {title}
  &lt;/li>
 );
});

const App = () => {
 const [items, setItems] = useState([
  {id: 1, title: 'Apfel', isHighlighted: false},
  {id: 2, title: 'Banane', isHighlighted: false},
  {id: 3, title: 'Kirsche', isHighlighted: false},
 ]);
 const [count, setCount] = useState(0);

 const toggleHighlight = (id) => {
  setItems(items.map(item =>
   item.id === id ? {...item, isHighlighted: !item.isHighlighted} : item
  ));
 };

 return (
  &lt;div>
   &lt;ul>
    {items.map(item => (
     &lt;ListItem
      key={item.id}
      title={item.title}
      isHighlighted={item.isHighlighted}
     />
    ))}
   &lt;/ul>
   &lt;button onClick={() => setCount(c => c + 1)}>
    Count: {count} (kein Re-render der Items!)
   &lt;/button>
   &lt;button onClick={() => toggleHighlight(1)}>
    Apfel hervorheben
   &lt;/button>
  &lt;/div>
 );
}

export default App

import React, { useState, memo, useCallback } from 'react';

const Display = memo(({ count, onIncrement }) => {
 console.log("Display gerendert"); // Loggt NUR, wenn count sich ändert
 return (
  &lt;div>
   &lt;p>Count: {count}&lt;/p>
   &lt;button onClick={onIncrement}>+1&lt;/button>
  &lt;/div>
 );
});

const App = () => {
 const [count, setCount] = useState(0);
 const [otherState, setOtherState] = useState(false);

 // Mit useCallback: Funktion bleibt stabil
 const increment = useCallback(() => {
  setCount(c => c + 1);
 }, []); // Leeres Array: Funktion wird nie neu erstellt

 return (
  &lt;div>
   &lt;Display count={count} onIncrement={increment} />
   &lt;button onClick={() => setOtherState(!otherState)}>
    Anderen State ändern (kein Re-render von Display!)
   &lt;/button>
  &lt;/div>
 );
}
export default App
